Query:
SELECT COUNT(*) AS reopen_count
FROM ai.calibrationmasterdetails cm
WHERE cm.calibration_status in ('Reopened') AND cm.calibration_facility_code in ('ATC-GJ');

SELECT calibration_id,calibration_date
 FROM ai.calibrationmasterdetails
 WHERE calibration_facility_code in ('ATC-GJ') order by calibration_date,calibration_id desc limit 1;

SELECT COUNT(*)
 FROM ai.calibrationmasterdetails
 WHERE calibration_category ilike '%internal%' and calibration_facility_code in ('SRP-WPB-PKG');

SELECT calibration_id, calibration_instrument_name, calibration_category, calibration_facility_code, calibration_status
 FROM ai.calibrationmasterdetails
 WHERE calibration_status in ('Initiated') and calibration_facility_code in ('SRP-WPB-PKG');

SELECT COUNT(*)
 FROM ai.calibrationmasterdetails
 WHERE calibration_status in ('Cancelled') and calibration_facility_code in ('SRP-WPB-PKG');

SELECT COUNT(*)
 FROM ai.calibrationmasterdetails
 WHERE calibration_status in ('Reopened') and calibration_facility_code in ('SRP-WPB-PKG');

SELECT calibration_id, calibration_instrument_name, calibration_category, calibration_facility_code, calibration_status,calibration_assigned_to_user FROM ai.calibrationmasterdetails
WHERE calibration_category = 'Critical'
AND calibration_facility_code in ('SRP-WPB-PKG');

SELECT instrument_name, instrument_code, instrument_critical
FROM ai.instrument_master
WHERE instrument_critical = 'true' and instrument_located_at_facility_code in ('MYS-PB-REAC AND PE','MYS-MATERIALS','MYS-PB-GENERAL','MYS-WPB-PRS');

SELECT instrument_name, instrument_is_part_of_equipment
FROM ai.instrument_master
WHERE COALESCE(instrument_is_part_of_equipment, '') != '' and instrument_located_at_facility_code in ('MYS-PB-REAC AND PE','MYS-MATERIALS','MYS-PB-GENERAL','MYS-WPB-PRS');

SELECT instrument_name, instrument_code, instrument_installation_date
FROM ai.instrument_master
WHERE instrument_installation_date < '2022-01-01' and instrument_located_at_facility_code in ('MYS-PB-REAC AND PE','MYS-MATERIALS','MYS-PB-GENERAL','MYS-WPB-PRS');

SELECT instrument_name, instrument_code
FROM ai.instrument_master
WHERE COALESCE(instrument_barcode, '') != '' and instrument_located_at_facility_code in ('MYS-PB-REAC AND PE','MYS-MATERIALS','MYS-PB-GENERAL','MYS-WPB-PRS');

SELECT instrument_name, instrument_code,instrument_status
FROM ai.instrument_master
WHERE instrument_status ilike '%Discarded%' and instrument_located_at_facility_code in ('MYS-PB-REAC AND PE','MYS-MATERIALS','MYS-PB-GENERAL','MYS-WPB-PRS');

SELECT calibration_id, calibration_instrument_name, calibration_instrument_code, calibration_malfunction_reported, calibration_malfunction_reported_description
FROM ai.calibrationmasterdetails
WHERE calibration_malfunction_reported = 'true' and calibration_facility_code in ('MYS-PB-REAC AND PE','MYS-MATERIALS','MYS-PB-GENERAL','MYS-WPB-PRS');

SELECT m.calibration_flow_meter_master_instrument_observation_calibratio AS calibration_id, m.calibration_flow_meter_master_instrument_observation_actual AS master_actual_value, t.calibration_flow_meter_test_instrument_observation_actual AS test_actual_value, ABS(
CAST(m.calibration_flow_meter_master_instrument_observation_actual AS NUMERIC) - CAST(t.calibration_flow_meter_test_instrument_observation_actual AS NUMERIC)
) AS difference FROM ai.calibration_flow_meter_master_instrument_observation m JOin ai.calibration_flow_meter_test_instrument_observation t ON m.calibration_flow_meter_master_instrument_observation_calibratio = t.calibration_flow_meter_test_instrument_observation_calibration_ LEFT JOin ai.calibrationmasterdetails d ON m.calibration_flow_meter_master_instrument_observation_calibratio = d.calibration_id
WHERE TRIM(m.calibration_flow_meter_master_instrument_observation_actual::TEXT) <> '' AND TRIM(t.calibration_flow_meter_test_instrument_observation_actual::TEXT) <> '' AND m.calibration_flow_meter_master_instrument_observation_actual::TEXT ~ '^[0-9]*\.?[0-9]+$' AND t.calibration_flow_meter_test_instrument_observation_actual::TEXT ~ '^[0-9]*\.?[0-9]+$' AND d.calibration_facility_code in (
'MYS-PB-REAC AND PE', 'MYS-MATERIALS', 'MYS-PB-GENERAL', 'MYS-WPB-PRS');

SELECT COUNT(*) FROM ai.spareparts_master JOIN ai.spareparts_store_wise_stock ON spareparts_master.spareparts_part_code = spareparts_store_wise_stock.spareparts_store_wise_stock_part_code JOIN ai.facilitylinkstore
ON spareparts_store_wise_stock.spareparts_store_wise_stock_store_code = ai.facilitylinkstore.facilitylink_storecode
WHERE spareparts_store_wise_stock.spareparts_store_wise_stock_store_code IN ('1106-ENG4') AND spareparts_master.spareparts_part_activestatus = TRUE AND ai.facilitylinkstore.facilitylink_facility_code IN ('SRP-WPB');

SELECT spareparts_part_name, spareparts_part_description FROM ai.spareparts_master JOIN ai.spareparts_store_wise_stock ON spareparts_part_code = spareparts_store_wise_stock_part_code JOIN ai.facilitylinkstore
ON spareparts_store_wise_stock_store_code = ai.facilitylinkstore.facilitylink_storecode
WHERE spareparts_part_name ILIKE '%Motor%' AND spareparts_store_wise_stock_store_code IN ('1106-ENG4') AND ai.facilitylinkstore.facilitylink_facility_code IN ('SRP-WPB');

SELECT spareparts_part_code, spareparts_part_name, spareparts_part_category FROM ai.spareparts_master JOIN ai.spareparts_store_wise_stock ON spareparts_part_code = spareparts_store_wise_stock_part_code JOIN ai.facilitylinkstore
ON spareparts_store_wise_stock_store_code = ai.facilitylinkstore.facilitylink_storecode
WHERE spareparts_part_category IN ('Electrical', 'Mechanical', 'Plumbing') AND spareparts_store_wise_stock_store_code IN ('1106-ENG4') AND ai.facilitylinkstore.facilitylink_facility_code IN ('SRP-WPB');

SELECT spareparts_part_code, spareparts_part_name, spareparts_part_created_time FROM ai.spareparts_master JOIN ai.spareparts_store_wise_stock ON spareparts_part_code = spareparts_store_wise_stock_part_code JOIN ai.facilitylinkstore
ON spareparts_store_wise_stock_store_code = ai.facilitylinkstore.facilitylink_storecode
WHERE spareparts_part_created_time BETWEEN '2023-01-01' AND '2023-12-31' AND spareparts_store_wise_stock_store_code IN ('1106-ENG4') AND ai.facilitylinkstore.facilitylink_facility_code IN ('SRP-WPB');

SELECT workorder_checklist_plannedeffort FROM ai.workorder_checklist JOin ai.workordermasterdetails ON workorder_checklist.workorder_checklist_workorder_id = workordermasterdetails.workorder_id
WHERE workorder_checklist_workorder_id = 'WO099995' AND workorder_checklist_taskdescription ilike '%Check%for%any%abnormal%noise%'
AND workordermasterdetails.workorder_facility_code in ('MYS-PMG-ASRS');

SELECT workorder_checklist_mandatory FROM ai.workorder_checklist JOin ai.workordermasterdetails ON workorder_checklist.workorder_checklist_workorder_id = workordermasterdetails.workorder_id
WHERE workorder_checklist_workorder_id = 'WO099995' AND workorder_checklist_taskdescription  ilike '%Check%for%any%abnormal%noise%'
AND workordermasterdetails.workorder_facility_code in ('MYS-PMG-ASRS');

SELECT COUNT(*) FROM ai.workorder_checklist JOin ai.workordermasterdetails ON workorder_checklist.workorder_checklist_workorder_id = workordermasterdetails.workorder_id
WHERE workorder_checklist_workorder_id = 'WO099995' AND workorder_checklist_completionstatus = TRUE
AND workordermasterdetails.workorder_facility_code in ('MYS-PMG-ASRS');

SELECT COUNT(*) FROM ai.workorder_checklist JOin ai.workordermasterdetails ON workorder_checklist.workorder_checklist_workorder_id = workordermasterdetails.workorder_id
WHERE workorder_checklist_workorder_id = 'WO099995'
AND workordermasterdetails.workorder_facility_code in ('MYS-PMG-ASRS');

SELECT COUNT(*) FROM ai.workordermasterdetails
WHERE workorder_has_rca_mandatory = 't' and workorder_is_rca_completed ='f'
AND workorder_facility_code in ('1011- CBU-STC-001','1011-UTIL-WTP-FRO','1011-UTIL-STM-OTH');

SELECT sum(workorder_spareparts_quantity::numeric * workorder_spareparts_unitprice::numeric) as cost FROM ai.spareparts_store_wise_stock
 JOIN ai.workorder_spareparts ws ON spareparts_store_wise_stock_part_code = ws.workorder_spareparts_partcode 
 WHERE spareparts_store_wise_stock_store_code in ('ATC-GJ') and workorder_spareparts_createdtime >= CURRENT_DATE - INTERVAL '1 month';
